protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Blog>(entity =>
    {
        // Breaking change 1: EF 9 renamed discriminator property from "Discriminator" to "$type".
        // Existing documents use "Discriminator", so preserve the old name.
        entity.HasDiscriminator<string>("Discriminator");

        // Breaking change 2: EF 9 no longer prefixes the Cosmos id with the discriminator.
        // Existing documents have id format "Blog|{key}"; preserve it via a converter.
        entity.Property(b => b.Id).HasConversion(
            id => "Blog|" + id,
            id => id.StartsWith("Blog|") ? id.Substring(5) : id
        );

        // Breaking change 3: HasIndex() now throws for Cosmos (indexes are not supported).
        // Removed the previous HasIndex(b => b.Name) call.
    });
}

